body:
  if (!envPort) {
    return DEFAULT_DEMO_PORT
  }

  const parsedPort = Number.parseInt(envPort, 10)
  const isValidPort =
    Number.isInteger(parsedPort) && parsedPort > 0 && parsedPort <= 65535

  if (!isValidPort) {
    throw new Error(
      `Invalid DEMO_PORT "${envPort}". Expected an integer between 1 and 65535.`,
    )
  }

  return parsedPort
}

  const client = new QueryClient({
    defaultOptions: {
      queries: {
        retry: false,
        staleTime: Number.POSITIVE_INFINITY,
      },
    },
  })

  client.setQueryData(contractQueryKey, data)
  return client
}

  await delay(90)
  if (failNextFetch) {
    failNextFetch = false
    throw new Error('Forced fetch failure (test)')
  }
  requestCount += 1

  return {
    items: todos.map((todo) => ({ ...todo })),
    requestCount,
    source: 'server',
  }
}

  await delay(70)
  if (failNextMutation) {
    failNextMutation = false
    throw new Error('Forced mutation failure (test)')
  }

  const nextTodo: Todo = {
    id: nextTodoId,
    title,
  }

  nextTodoId += 1
  todos = [...todos, nextTodo]

  return { ...nextTodo }
}

  const rawValue = process.env[name]
  if (!rawValue) {
    return fallback
  }

  const parsed = Number.parseInt(rawValue, 10)
  const valid = Number.isInteger(parsed) && parsed >= 1 && parsed <= 65_535

  if (!valid) {
    throw new Error(
      `Invalid ${name}="${rawValue}". Expected integer in [1, 65535].`,
    )
  }

  return parsed
}

  stream.on('data', (chunk) => {
    output.write(`${prefix}${chunk}`)
  })
}

  const child = spawn(command, args, {
    cwd,
    stdio: ['ignore', 'pipe', 'pipe'],
    env: {
      ...process.env,
      ...extraEnv,
    },
  })

  forwardOutput(`[${name}] `, child.stdout, process.stdout)
  forwardOutput(`[${name}] `, child.stderr, process.stderr)

  return child
}

  if (!child || child.exitCode !== null) {
    return
  }

  child.kill('SIGTERM')
  await Promise.race([
    once(child, 'exit'),
    new Promise((resolve) => setTimeout(resolve, 2000)),
  ])

  if (child.exitCode === null) {
    child.kill('SIGKILL')
    await Promise.race([
      once(child, 'exit'),
      new Promise((resolve) => setTimeout(resolve, 2000)),
    ])
  }
}

  const api = start('api', process.execPath, ['./server/index.mjs'])
  const web = start('web', viteCommand, [], {
    VITE_PAGINATION_API_PORT: String(API_PORT),
  })

  const shutdown = async () => {
    await Promise.all([stop(web), stop(api)])
  }

  process.on('SIGINT', shutdown)
  process.on('SIGTERM', shutdown)

  const [winner] = await Promise.race([
    once(api, 'exit').then(([code]) => ({ name: 'api', code })),
    once(web, 'exit').then(([code]) => ({ name: 'web', code })),
  ])

  await shutdown()

  if (winner.code !== 0 && winner.code !== null) {
    process.exitCode = winner.code
  } else {
    process.exitCode = 1
  }
}

  return Array.from({ length: TOTAL_PROJECTS }, (_, index) => ({
    id: index + 1,
    name: `Project ${index + 1}`,
    owner: `Team ${(index % 5) + 1}`,
    isFavorite: false,
  }))
}

  const payload = JSON.stringify(body)
  res.writeHead(status, {
    'content-type': 'application/json; charset=utf-8',
    'cache-control': 'no-store',
    'access-control-allow-origin': '*',
    'access-control-allow-methods': 'GET,POST,PATCH,OPTIONS',
    'access-control-allow-headers': 'content-type',
    'content-length': Buffer.byteLength(payload),
  })
  res.end(payload)
}

  if (rawValue == null || rawValue === '') {
    return fallback
  }

  const parsed = Number.parseInt(rawValue, 10)
  if (!Number.isInteger(parsed) || parsed < 1) {
    return undefined
  }

  return parsed
}

  if (rawValue == null || rawValue === '') {
    return fallback
  }

  const parsed = Number.parseInt(rawValue, 10)
  if (!Number.isInteger(parsed) || parsed < 0) {
    return undefined
  }

  return parsed
}

  if (!ms || ms <= 0) {
    return
  }

  await new Promise((resolve) => {
    setTimeout(resolve, ms)
  })
}

  const contentType = req.headers['content-type']
  if (!contentType || !contentType.startsWith(JSON_CONTENT_TYPE)) {
    return {
      ok: false,
      status: 415,
      error: 'Expected application/json request body',
    }
  }

  const chunks = []
  for await (const chunk of req) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk))
  }

  const raw = Buffer.concat(chunks).toString('utf8')
  if (!raw) {
    return {
      ok: false,
      status: 400,
      error: 'Request body is required',
    }
  }

  try {
    return {
      ok: true,
      value: JSON.parse(raw),
    }
  } catch {
    return {
      ok: false,
      status: 400,
      error: 'Request body must be valid JSON',
    }
  }
}

  const totalPages = Math.max(1, Math.ceil(projects.length / PAGE_SIZE))
  const boundedPage = Math.min(page, totalPages)
  const startIndex = (boundedPage - 1) * PAGE_SIZE
  const endIndex = startIndex + PAGE_SIZE
  const items = projects.slice(startIndex, endIndex)

  totalRequestCount += 1
  const pageRequests = (perPageRequestCount.get(boundedPage) ?? 0) + 1
  perPageRequestCount.set(boundedPage, pageRequests)

  return {
    page: boundedPage,
    pageSize: PAGE_SIZE,
    totalPages,
    totalProjects: projects.length,
    hasMore: boundedPage < totalPages,
    projects: items,
    requestMeta: {
      totalRequestCount,
      pageRequestCount: pageRequests,
      totalMutationCount,
    },
  }
}

  if (!failNextMutation) {
    return false
  }

  failNextMutation = false
  writeJson(res, 500, { error: 'Forced mutation failure (test)' })
  return true
}

  if (typeof name !== 'string') {
    return 'Project name must be a string'
  }

  const trimmed = name.trim()
  if (trimmed.length < 3) {
    return 'Project name must be at least 3 characters'
  }

  if (trimmed.length > 60) {
    return 'Project name must be 60 characters or fewer'
  }

  return null
}

  if (typeof owner !== 'string') {
    return 'Owner must be a string'
  }

  const trimmed = owner.trim()
  if (!trimmed) {
    return 'Owner is required'
  }

  if (trimmed.length > 40) {
    return 'Owner must be 40 characters or fewer'
  }

  return null
}

  const url = new URL('/api/projects', API_BASE_URL)
  url.searchParams.set('page', String(page))

  if (delayMs > 0) {
    url.searchParams.set('delay', String(delayMs))
  }

  if (forceError) {
    url.searchParams.set('error', 'true')
  }

  return url
}

  const response = await fetch(buildProjectsUrl(page, delayMs, forceError))
  return readJsonOrThrow<ProjectsPageResponse>(
    response,
    `Failed to fetch projects page ${page}`,
  )
}

  return requestJson<ProjectMutationResponse>(
    new URL('/api/projects', API_BASE_URL),
    {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
      },
      body: JSON.stringify(input),
    },
