  )
}

  return requestJson<ProjectMutationResponse>(
    new URL(`/api/projects/${input.id}`, API_BASE_URL),
    {
      method: 'PATCH',
      headers: {
        'content-type': 'application/json',
      },
      body: JSON.stringify({ isFavorite: input.isFavorite }),
    },
    `Failed to update project ${input.id}`,
  )
}

  await requestJson<{ ok: true }>(
    new URL('/api/testing/fail-next-mutation', API_BASE_URL),
    {
      method: 'POST',
    },
    'Failed to arm next mutation failure',
  )
}

  await requestJson<{ ok: true }>(
    new URL('/api/reset', API_BASE_URL),
    {
      method: 'POST',
    },
    'Failed to reset API state',
  )
}

  if (host.includes(':') && !host.startsWith('[') && !host.endsWith(']')) {
    return `[${host}]`
  }

  return host
}

  const value = process.env[name]
  if (!value) {
    return fallback
  }

  const parsedPort = Number.parseInt(value, 10)
  const isValidPort =
    Number.isInteger(parsedPort) && parsedPort > 0 && parsedPort <= 65_535

  if (!isValidPort) {
    throw new Error(
      `Invalid ${name} "${value}". Expected an integer between 1 and 65535.`,
    )
  }

  return parsedPort
}

  if (host === '0.0.0.0') {
    return '127.0.0.1'
  }

  if (host === '::') {
    return '[::1]'
  }

  return normalizeUrlHost(host)
}

  const explicitOrigin = process.env.SSR_PUBLIC_ORIGIN
  if (explicitOrigin) {
    const url = new URL(explicitOrigin)
    return url.origin
  }

  const explicitPublicHost = process.env.SSR_PUBLIC_HOST
  const publicHost = explicitPublicHost
    ? normalizeUrlHost(explicitPublicHost)
    : resolveConnectHost(host)

  return `http://${publicHost}:${port}`
}

  const result = spawnSync(npmCommand, ['run', 'build'], {
    cwd,
    stdio: 'inherit',
  })

  if (result.status !== 0) {
    process.exit(result.status ?? 1)
  }
}

  runBuild()

  const server = spawn(tsxCommand, ['./server/index.mjs'], {
    cwd,
    stdio: 'inherit',
  })

  const stopServer = (signal) => {
    if (server.exitCode === null) {
      server.kill(signal)
    }
  }

  process.on('SIGINT', () => stopServer('SIGINT'))
  process.on('SIGTERM', () => stopServer('SIGTERM'))

  const outcome = await Promise.race([
    once(server, 'error').then(([error]) => {
      throw error
    }),
    once(server, 'exit').then(([code]) => ({ code })),
  ])

  process.exitCode = outcome.code ?? 0
}

  if (server.exitCode === null) {
    server.kill(signal)
  }
}

  return new QueryClient({
    defaultOptions: {
      queries: {
        retry: false,
        staleTime: QUERY_STALE_TIME,
      },
    },
  })
}

  requestCount += 1
  return {
    message: DEFAULT_MESSAGE,
    requestCount,
    servedAt: new Date().toISOString(),
  }
}

  const parsedDelayMs = Number.parseInt(value ?? '', 10)
  if (!Number.isInteger(parsedDelayMs) || parsedDelayMs < 0) {
    return undefined
  }

  return parsedDelayMs
}

  const delayMs = nextDataDelayMs
  nextDataDelayMs = 0

  if (delayMs > 0) {
    await sleep(delayMs)
  }
}

  if (!failNextDataRequest) {
    return false
  }

  failNextDataRequest = false
  return true
}

  res.writeHead(statusCode, {
    'cache-control': 'no-store',
    'content-length': payload.byteLength,
    'content-type': contentType,
    ...extraHeaders,
  })
  res.end(payload)
}

  const payload = Buffer.from(body)
  writeBuffer(
    res,
    statusCode,
    'text/html; charset=utf-8',
    payload,
    extraHeaders,
  )
}

  const payload = Buffer.from(JSON.stringify(body))
  writeBuffer(
    res,
    statusCode,
    'application/json; charset=utf-8',
    payload,
    apiCorsHeaders,
