}

  if (!pathname.startsWith('/assets/')) {
    return false
  }

  const assetPath = resolve(distDir, `.${pathname}`)
  const distRootPrefix = `${distDir}${sep}`
  if (!assetPath.startsWith(distRootPrefix)) {
